import { useState, useEffect, useRef } from 'react';
import { Handle, Position } from 'reactflow';

const VAR_REGEX = /{{\s*([a-zA-Z_$][a-zA-Z0-9_$]*)\s*}}/g;

export default function TextNode({ id, data }) {
  const [text, setText] = useState(data?.text || '');
  const [variables, setVariables] = useState([]);
  const textareaRef = useRef(null);

  // Extract unique {{variables}} from text
  useEffect(() => {
    const matches = [...text.matchAll(VAR_REGEX)];
    const unique = [...new Set(matches.map((m) => m[1]))];
    setVariables(unique);
  }, [text]);

  // Auto-resize textarea height
  useEffect(() => {
    const el = textareaRef.current;
    if (el) {
      el.style.height = 'auto';
      el.style.height = `${el.scrollHeight}px`;
    }
  }, [text]);

  const handleStyle = (index, total) => ({
    top: `${((index + 1) / (total + 1)) * 100}%`,
  });

  return (
    <div className="base-node">
      <div className="base-node-header">
        <span className="base-node-header-dot" />
        <span className="base-node-title">Text</span>
      </div>

      <div className="base-node-body">
        <textarea
          ref={textareaRef}
          value={text}
          onChange={(e) => setText(e.target.value)}
          rows={2}
          placeholder="Use {{variable}} syntax…"
          style={{ resize: 'none', overflow: 'hidden' }}
        />
      </div>

      {/* Dynamic input handles — one per {{variable}} */}
      {variables.map((varName, i) => (
        <div key={varName}>
          <Handle
            type="target"
            position={Position.Left}
            id={`${id}-${varName}`}
            style={handleStyle(i, variables.length)}
          />
          <span
            className="handle-label handle-label-left"
            style={{ top: `${((i + 1) / (variables.length + 1)) * 100}%` }}
          >
            {varName}
          </span>
        </div>
      ))}

      {/* Static output handle */}
      <Handle
        type="source"
        position={Position.Right}
        id={`${id}-output`}
        style={{ top: '50%' }}
      />
      <span className="handle-label handle-label-right" style={{ top: '50%' }}>
        out
      </span>
    </div>
  );
}
